hooks.command:
python3 -c "
import sys, json, re
UV_RUN_TOOLS = ('pytest', 'ruff', 'pyright', 'basedpyright', 'ty')
d = json.load(sys.stdin)
cmd = d.get('tool_input', {}).get('command', '')
n = cmd
if cmd and not cmd.startswith('uv '):
    if m := re.match(r'^python3? -m (.+)$', cmd): n = 'uv run -m ' + m[1]
    elif m := re.match(r'^python3?(\\s.*)?$', cmd): n = 'uv run python' + (m[1] or '')
    elif m := re.match(r'^pip3? install(\\s.*)?$', cmd): n = 'uv add' + (m[1] or '')
    elif m := re.match(r'^pip3? uninstall(\\s.*)?$', cmd): n = 'uv remove' + (m[1] or '')
    elif m := re.match(r'^pip3? (.+)$', cmd): n = 'uv pip ' + m[1]
    elif m := re.match(r'^(' + '|'.join(re.escape(t) for t in UV_RUN_TOOLS) + r')(\\s.*)?$', cmd): n = 'uv run ' + m[1] + (m[2] or '')
if n != cmd:
    d['tool_input']['command'] = n
    print(json.dumps({'hookSpecificOutput': {'hookEventName': 'PreToolUse', 'updatedInput': d['tool_input']}}))
"
